static const char LIB_FS[] = "// std.fs — Operaciones nativas del sistema de archivos via FFI\n// Integrante de la Biblioteca Estandar de Synapse.\n//\n// Uso desde Synapse:\n//   importar std.fs\n//   a = abrir_archivo(\"test.txt\", \"w\")\n//   escribir_archivo(a, \"hola mundo\")\n//   cerrar_archivo(a)\n//\n// Nota: Los handles de archivo se almacenan como enteros opacos.\n//       La implementacion subyacente usa FILE* de C.\n\nimportar_c \"<stdio.h>\"\n\n// Tipo envoltorio para FILE* de C (almacenado como entero opaco)\nestructura Archivo:\n    handle: entero\n\n// Declaraciones externas de C standard library\nexterno funcion fopen(ruta: char*, modo: char*) -> entero\nexterno funcion fclose(archivo: entero) -> entero\nexterno funcion fputs(str: char*, archivo: entero) -> entero\n\n// Wrappers nativos en Synapse\n\nfuncion abrir_archivo(ruta: texto, modo: texto) -> Archivo:\n    a = Archivo()\n    a.handle = fopen(ruta, modo)\n    retornar a\n\nfuncion cerrar_archivo(a: Archivo) -> entero:\n    retornar fclose(a.handle)\n\nfuncion escribir_archivo(a: Archivo, contenido: texto) -> entero:\n    retornar fputs(contenido, a.handle)\n";
